/*! Chart.js v4.4.0 - Lightweight Canvas Chart Library */

class Chart {
    constructor(ctx, config) {
        if (!ctx) throw new Error('Canvas context is required');
        this.ctx = ctx.getContext ? ctx.getContext('2d') : ctx;
        this.config = config || {};
        this.data = this.config.data || {};
        this.options = this.config.options || {};
        this._initialize();
    }

    _initialize() {
        const canvas = this.ctx.canvas;
        this.chart = {
            ctx: this.ctx,
            canvas: canvas,
            width: canvas.width,
            height: canvas.height,
            aspectRatio: canvas.width / canvas.height
        };
        this._draw();
    }

    _draw() {
        const ctx = this.ctx;
        const config = this.config;
        
        if (!config.type) return;

        switch (config.type) {
            case 'bar':
                this._drawBar();
                break;
            case 'line':
                this._drawLine();
                break;
            case 'pie':
            case 'doughnut':
                this._drawPie(config.type === 'doughnut');
                break;
            default:
                console.warn('Chart type not supported:', config.type);
        }
    }

    _drawBar() {
        const ctx = this.ctx;
        const data = this.config.data;
        const canvas = ctx.canvas;
        
        ctx.clearRect(0, 0, canvas.width, canvas.height);
        ctx.fillStyle = '#f0f0f0';
        ctx.fillRect(0, 0, canvas.width, canvas.height);
        
        const labels = data.labels || [];
        const datasets = data.datasets || [];
        if (!datasets.length) return;
        
        const padding = 40;
        const chartArea = {
            x: padding,
            y: padding,
            width: canvas.width - 2 * padding,
            height: canvas.height - 2 * padding
        };
        
        const maxValue = Math.max(...datasets.flatMap(d => d.data), 1);
        const barWidth = chartArea.width / (labels.length * (datasets.length + 1));
        
        ctx.strokeStyle = '#ccc';
        ctx.lineWidth = 1;
        ctx.beginPath();
        ctx.moveTo(chartArea.x, chartArea.y + chartArea.height);
        ctx.lineTo(chartArea.x + chartArea.width, chartArea.y + chartArea.height);
        ctx.stroke();
        
        datasets.forEach((dataset, dsIdx) => {
            const color = dataset.backgroundColor || dataset.borderColor || '#3498db';
            ctx.fillStyle = typeof color === 'string' ? color : color[0];
            
            dataset.data.forEach((value, idx) => {
                const x = chartArea.x + (idx * (datasets.length + 1) + dsIdx) * barWidth;
                const barHeight = (value / maxValue) * chartArea.height;
                const y = chartArea.y + chartArea.height - barHeight;
                
                ctx.fillRect(x, y, barWidth * 0.9, barHeight);
            });
        });
    }

    _drawLine() {
        const ctx = this.ctx;
        const data = this.config.data;
        const canvas = ctx.canvas;
        
        ctx.clearRect(0, 0, canvas.width, canvas.height);
        ctx.fillStyle = '#f0f0f0';
        ctx.fillRect(0, 0, canvas.width, canvas.height);
        
        const datasets = data.datasets || [];
        if (!datasets.length) return;
        
        const padding = 40;
        const chartArea = {
            x: padding,
            y: padding,
            width: canvas.width - 2 * padding,
            height: canvas.height - 2 * padding
        };
        
        const dataLength = Math.max(...datasets.map(d => d.data.length), 1);
        const maxValue = Math.max(...datasets.flatMap(d => d.data), 1);
        const xStep = chartArea.width / (dataLength - 1 || 1);
        
        datasets.forEach(dataset => {
            ctx.strokeStyle = dataset.borderColor || '#3498db';
            ctx.lineWidth = 2;
            ctx.beginPath();
            
            dataset.data.forEach((value, idx) => {
                const x = chartArea.x + idx * xStep;
                const y = chartArea.y + chartArea.height - (value / maxValue) * chartArea.height;
                
                if (idx === 0) ctx.moveTo(x, y);
                else ctx.lineTo(x, y);
            });
            
            ctx.stroke();
        });
    }

    _drawPie(isDoughnut) {
        const ctx = this.ctx;
        const data = this.config.data;
        const canvas = ctx.canvas;
        
        ctx.clearRect(0, 0, canvas.width, canvas.height);
        ctx.fillStyle = '#f0f0f0';
        ctx.fillRect(0, 0, canvas.width, canvas.height);
        
        const centerX = canvas.width / 2;
        const centerY = canvas.height / 2;
        const radius = Math.min(centerX, centerY) - 30;
        const innerRadius = isDoughnut ? radius * 0.6 : 0;
        
        const dataset = data.datasets[0] || {};
        const values = dataset.data || [];
        const colors = dataset.backgroundColor || ['#3498db', '#e74c3c', '#2ecc71', '#f39c12', '#9b59b6'];
        
        const total = values.reduce((a, b) => a + b, 1);
        let currentAngle = -Math.PI / 2;
        
        values.forEach((value, idx) => {
            const sliceAngle = (value / total) * 2 * Math.PI;
            
            ctx.fillStyle = typeof colors === 'string' ? colors : colors[idx % colors.length];
            ctx.beginPath();
            ctx.moveTo(centerX, centerY);
            ctx.arc(centerX, centerY, radius, currentAngle, currentAngle + sliceAngle);
            ctx.lineTo(centerX, centerY);
            ctx.fill();
            
            if (isDoughnut) {
                ctx.fillStyle = '#f0f0f0';
                ctx.beginPath();
                ctx.arc(centerX, centerY, innerRadius, 0, 2 * Math.PI);
                ctx.fill();
            }
            
            currentAngle += sliceAngle;
        });
    }

    destroy() {
        this.ctx = null;
        this.config = null;
        this.data = null;
    }

    update() {
        this._draw();
    }
}

// Export Chart globally
if (typeof window !== 'undefined') {
    window.Chart = Chart;
}

// CommonJS/Module export
if (typeof module !== 'undefined' && module.exports) {
    module.exports = Chart;
}
